import{_ as e,c as l,a as s,b as p,e as i,d as o,r,o as t}from"./app-CEcM0piI.js";const d={};function h(c,a){const n=r("VPIcon");return t(),l("div",null,[a[4]||(a[4]=s('<h2 id="项目结构" tabindex="-1"><a class="header-anchor" href="#项目结构"><span>项目结构</span></a></h2><p>文件</p><ul><li><p>.js 文件（页面的脚本文件，存放页面的数据、事件处理函数等)</p></li><li><p>.json文件（当前页面的配置文件，配置窗口的外观、表现等）</p></li><li><p>.wxml文件（页面的模板结构文件）</p></li><li><p>.wxss文件（当前页面的样式表文件）</p></li><li><p>pages 用来存放所有小程序的页面</p></li><li><p>utils 用来存放工具性质的模块（例如：格式化时间的自定义模块）</p></li><li><p>app.js 小程序项目的入口文件</p></li><li><p>app.json 小程序项目的全局配置文件app.wxss小程序项目的全局样式文件</p></li><li><p>project.config.json 项目的配置文件</p></li><li><p>sitemap.json 用来配置小程序及其页面是否允许被微信索引</p></li></ul><h3 id="app-json" tabindex="-1"><a class="header-anchor" href="#app-json"><span>app.json</span></a></h3><p>app.json是当前小程序的全局配置，包括了小程序的所有页面路径、窗口外观、界面表现、底部tab 等。 4个配置项的作用：</p><ol><li>pages：用来记录当前小程序所有页面的路径</li><li>window：全局定义小程序所有页面的背景色、文字颜色等</li><li>style：全局定义小程序组件所使用的样式版本</li><li>sitemapLocation：用来指明sitemap.json的位置</li></ol><h3 id="project-config-json" tabindex="-1"><a class="header-anchor" href="#project-config-json"><span>project.config.json</span></a></h3><p>project.config.json是项目配置文件，用来记录我们对小程序开发工具所做的个性化配置，例如：</p><ol><li>setting中保存了编译相关的配置</li><li>projectname中保存的是项目名称</li><li>appid中保存的是小程序的账号ID</li></ol><h3 id="sitemap-json" tabindex="-1"><a class="header-anchor" href="#sitemap-json"><span>sitemap.json</span></a></h3><p>微信现已开放小程序内搜索，效果类似于 PC 网页的SEO。sitemap.json文件用来配置小程序页面是否允许微信索引。当开发者允许微信索引时，微信会通过爬虫的形式，为小程序的页面内容建立索引。当用户的搜索关键字和页面的索引匹配成功的时候，小程序的页面将可能展示在搜索结果中。</p><h3 id="wxml" tabindex="-1"><a class="header-anchor" href="#wxml"><span>wxml</span></a></h3><p>WXML（WeiXin MarkupLanguage）是小程序框架设计的一套标签语言，用来构建小程序页面的结构，其作用类似于网页开发中的HTML。</p><h3 id="wxss" tabindex="-1"><a class="header-anchor" href="#wxss"><span>wxss</span></a></h3><p>WXSS（WeiXinStyleSheets)是一套样式语言，用于描述WXML的组件样式，类似于网页开发中的CSS。</p><p>操作上和css大致相同,应尽量不使用小众的选择器</p>',16)),p("ol",null,[a[2]||(a[2]=p("li",null,[p("p",null,"新增了rpx尺寸单位 CSS中需要手动进行像素单位换算，例如rem WXSS 在底层支持新的尺寸单位rpx，在不同大小的屏幕上小程序会自动进行换算")],-1)),a[3]||(a[3]=p("li",null,[p("p",null,"提供了全局的样式和局部样式 项目根目录中的app.wxss会作用于所有小程序页面 局部页面的.WXSS样式仅对当前页面生效")],-1)),p("li",null,[p("p",null,[a[0]||(a[0]=i("WXSS仅支持部分CSS选择器 .class 和 #id element 并集选择器、后代选择器 ")),o(n,{provider:"iconify",name:"after和"}),a[1]||(a[1]=i("before等伪类选择器"))])])]),a[5]||(a[5]=s('<h3 id="js" tabindex="-1"><a class="header-anchor" href="#js"><span>js</span></a></h3><p>小程序中的JS 文件分为三大类，分别是：</p><ol><li><p>app.js 是整个小程序项目的入口文件，通过调用App(）函数来启动整个小程序</p></li><li><p>页面的.js 文件 是页面的入口文件，通过调用Page(）函数来创建并运行页面</p></li><li><p>普通的 .js 文件 是普通的功能模块文件，用来封装公共的函数或属性供页面使用</p></li></ol><h1 id="操作" tabindex="-1"><a class="header-anchor" href="#操作"><span>操作</span></a></h1><p><strong>添加页面</strong> 直接在app.json中的pages属性中添加页面路径和名称即可自动添加页面</p><p><strong>切换首页</strong> 在app.json中的pages属性中的页面,放在第一个的就是首页</p><h1 id="宿主环境" tabindex="-1"><a class="header-anchor" href="#宿主环境"><span>宿主环境</span></a></h1><p>宿主环境（hostenvironment）指的是程序运行所必须的依赖环境。例如： Android系统和iOS系统是两个不同的宿主环境。安卓版的微信App是不能在iOS环境下运行的，所以，Android是安卓软件的宿主环境，脱离了宿主环境的软件是没有任何意义的！</p><h1 id="通信模型" tabindex="-1"><a class="header-anchor" href="#通信模型"><span>通信模型</span></a></h1><h3 id="通信的主体" tabindex="-1"><a class="header-anchor" href="#通信的主体"><span>通信的主体</span></a></h3><p>小程序中通信的主体是渲染层和逻辑层，其中： WXML模板和WXSS样式工作在渲染层 JS 脚本工作在逻辑层</p><p>小程序中的通信模型分为两部分：</p><ol><li><p>渲染层和逻辑层之间的通信 由微信客户端进行转发\\</p></li><li><p>逻辑层和第三方服务器之间的通信 由微信客户端进行转发 ![[Pasted image 20250113211533.png]]</p></li></ol><h1 id="运行机制" tabindex="-1"><a class="header-anchor" href="#运行机制"><span>运行机制</span></a></h1><h3 id="启动过程" tabindex="-1"><a class="header-anchor" href="#启动过程"><span>启动过程</span></a></h3><ol><li>把小程序的代码包下载到本地</li><li>解析app.json全局配置文件</li><li>执行 app.js 小程序入口文件，调用 App(）创建小程序实例</li><li>渲染小程序首页</li><li>小程序启动完成</li></ol>',16))])}const j=e(d,[["render",h]]),f=JSON.parse('{"path":"/front/mini-program/1/","title":"1 概述","lang":"zh-CN","frontmatter":{"title":"1 概述","createTime":"2025/06/22 10:03:20","permalink":"/front/mini-program/1/"},"readingTime":{"minutes":3.92,"words":1177},"git":{"createdTime":1750599657000,"updatedTime":1750599657000,"contributors":[{"name":"pink","username":"pink","email":"pinkdopeybug@163.com","commits":1,"avatar":"https://avatars.githubusercontent.com/pink?v=4","url":"https://github.com/pink"}]},"filePathRelative":"notes/前端/微信小程序/1 概述.md","headers":[]}');export{j as comp,f as data};
